  const [name, setName] = useState('Tamil');

  // 1. No dependency array — every render-லயும் run ஆகும்
  useEffect(() => {
    console.log('Runs after every render');
  });

  // 2. Empty array — only on mount (componentDidMount equivalent)
  useEffect(() => {
    console.log('Runs only once — on mount');
    document.title = 'React App Loaded';
  }, []);

  // 3. With dependencies — count or name change ஆனப்போ run ஆகும்
  useEffect(() => {
    console.log(`count changed to: ${count}`);
    document.title = `Count: ${count}`;
