function SearchBar() {
  const inputRef = useRef(null);
  const countRef = useRef(0); // re-render இல்லாம count track

  // Component mount ஆனதும் auto focus
  useEffect(() => {
    inputRef.current.focus();
  }, []);

  const handleSearch = () => {
    countRef.current += 1; // state இல்ல, re-render இல்ல
    console.log(`Search triggered ${countRef.current} times`);
    const value = inputRef.current.value;
    console.log('Searching for:', value);
  };

  const handleClear = () => {
    inputRef.current.value = '';
    inputRef.current.focus();
  };

  return (
    <div>
      <input ref={inputRef} type="text" placeholder="Search..." />
      <button onClick={handleSearch}>Search</button>
      <button onClick={handleClear}>Clear</button>
    </div>
  );
}

import { useState, useRef, useEffect } from 'react';

function usePrevious(value) {
  const prevRef = useRef(undefined);

  useEffect(() => {
    prevRef.current = value;
  }); // no dependency — every render-ல் update ஆகும்

  return prevRef.current;
}

function Counter() {
  const [count, setCount] = useState(0);
  const prevCount = usePrevious(count);

  return (
    <div>
      <p>Current: {count}</p>
      <p>Previous: {prevCount ?? 'None'}</p>
      <button onClick={() => setCount(c => c + 1)}>Increment</button>
      <button onClick={() => setCount(c => c - 1)}>Decrement</button>
    </div>
  );
}

