import { Component } from 'react';

class ErrorBoundary extends Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  // Error catch பண்ணும்போது state update பண்றோம்
  static getDerivedStateFromError(error) {
    return { hasError: true, error };
  }

  // Error log பண்றோம் (analytics, Sentry போன்றவற்றுக்கு)
  componentDidCatch(error, errorInfo) {
    console.error('Error caught:', error, errorInfo);
    this.setState({ errorInfo });
    // logErrorToService(error, errorInfo);
  }

  handleReset = () => {
    this.setState({ hasError: false, error: null, errorInfo: null });
  };

  render() {
    if (this.state.hasError) {
      return (
        <div style={{ padding: '20px', background: '#fee', border: '1px solid red' }}>
          <h2>ஏதோ தவறு நடந்தது!</h2>
          <p>{this.state.error?.message}</p>
          <button onClick={this.handleReset}>மீண்டும் முயற்சி பண்ணவும்</button>
        </div>
      );
    }

    return this.props.children;
  }
}

export default ErrorBoundary;

